=Generate a full marketing plan for my business using the details below.
- Business Name: {{ $json['busness name'] }}
- Market Type: {{ $json['market type'] }}
- Country: {{ $json.country }}
- Budget: {{ $json.budget }}
- Goal: {{ $json.goal }}
Use the exact output format defined in your instructions. Tailor every section — channels, content, budget split, and weekly plan — specifically to the country and market type I provided. Express all monetary values in the correct local currency for that country.

parameters.jsCode:
const input =$('AI Agent').first().json.output ;

// ─── Cleanup: strip markdown noise from content ───────────────────────────────
function cleanContent(text) {
  return text
    .replace(/^#{1,6}\s*/gm, "")          // ## headings
    .replace(/^[-]{3,}\s*$/gm, "")        // --- dividers
    .replace(/^[=]{3,}\s*$/gm, "")        // === dividers
    .replace(/^[_]{3,}\s*$/gm, "")        // ___ dividers
    .replace(/^[*]{3,}\s*$/gm, "")        // *** dividers
    .replace(/\*\*(.*?)\*\*/g, "$1")      // **bold**
    .replace(/__(.*?)__/g, "$1")          // __bold__
    .replace(/\*(.*?)\*/g, "$1")          // *italic*
    .replace(/`{1,3}[^`]*`{1,3}/g, "")   // `code` or ```blocks```
    .replace(/\n{3,}/g, "\n\n")           // collapse excess blank lines
    .trim();
}

// ─── Section header patterns ──────────────────────────────────────────────────
const headerRegex = new RegExp(
  [
    /Marketing Plan\s*[–\-—][^\n]*/,
    /Marketing Strategy/,
    /Channels(?:\s*\(tailored to[^)]*\))?/,
    /Content Strategy/,
    /Paid Ads/,
    /30-Day Plan/,
  ]
    .map((r) => r.source)
    .join("|"),
  "gi"
);

// ─── Find all headers with their positions ────────────────────────────────────
const matches = [];
let match;
while ((match = headerRegex.exec(input)) !== null) {
  matches.push({ index: match.index, raw: match[0] });
}

// ─── Slice content between headers ───────────────────────────────────────────
const extracted = {};
for (let i = 0; i < matches.length; i++) {
  const { index, raw } = matches[i];
  const start = index + raw.length;
  const end = i + 1 < matches.length ? matches[i + 1].index : input.length;
  const content = cleanContent(input.slice(start, end)); // ← cleaned here

  const lowerRaw = raw.toLowerCase();
  if (/marketing plan/i.test(lowerRaw)) {
    const nameMatch = raw.match(/Marketing Plan\s*[–\-—]\s*(.+)/i);
    extracted.marketingPlanTitle = nameMatch ? nameMatch[1].trim() : "";
    extracted.marketingPlan = content;
  } else if (/marketing strategy/i.test(lowerRaw)) {
    extracted.marketingStrategy = content;
  } else if (/channels/i.test(lowerRaw)) {
    extracted.channels = content;
  } else if (/content strategy/i.test(lowerRaw)) {
    extracted.contentStrategy = content;
  } else if (/paid ads/i.test(lowerRaw)) {
    extracted.paidAds = content;
  } else if (/30-day plan/i.test(lowerRaw)) {
    extracted.thirtyDayPlan = content;
  }
}

// ─── n8n output ───────────────────────────────────────────────────────────────
return [
  {
    json: {
      marketingPlanTitle: extracted.marketingPlanTitle || "",
      marketingPlan:      extracted.marketingPlan      || "",
      marketingStrategy:  extracted.marketingStrategy  || "",
      channels:           extracted.channels           || "",
      contentStrategy:    extracted.contentStrategy    || "",
      paidAds:            extracted.paidAds            || "",
      thirtyDayPlan:      extracted.thirtyDayPlan      || "",
    },
  },
];

// Get inputs
const aiOutput = $input.first().json.output || "";
const inputCountry = $('On form submission').first().json.country || "";

// Prepare validation
let isValid = true;
let issues = [];

// 1. Check required sections in AI output
const requiredSections = [
  "Marketing Plan",
  "Market Analysis",
  "Marketing Strategy",
  "Channels",
  "Content Strategy",
  "Paid Ads",
  "30-Day Plan"
];

requiredSections.forEach(section => {
  if (!aiOutput.includes(section)) {
    isValid = false;
    issues.push(`Missing section: ${section}`);
  }
});

// 2. Check country consistency
// (basic check: country name must appear in output)
if (inputCountry) {
  if (!aiOutput.toLowerCase().includes(inputCountry.toLowerCase())) {
    isValid = false;
    issues.push(`Country mismatch: "${inputCountry}" not found in AI output`);
  }
} else {
  isValid = false;
  issues.push("Input country is missing");
}

// 3. Check basic formatting (Markdown style headings)
if (!aiOutput.includes("##")) {
  isValid = false;
  issues.push("Output is not properly formatted in Markdown (missing headings)");
}

// 4. Final result (n8n format)
if (isValid) {
  return [
    {
      json: {
        valid: true,
        message: "Output is valid"
      }
    }
  ];
} else {
  return [
    {
      json: {
        valid: false,
        issues: issues
      }
    }
  ];
}

